.pg-empty { grid-column:1/-1; text-align:center; padding:80px 20px; }
.pg-empty-icon { font-size:60px; display:block; margin-bottom:16px; }
.pg-empty h3 {
  font-family:'Cormorant Garamond',serif;
  font-size:1.5rem; font-weight:700; color:var(--text); margin:0 0 8px;
}
.pg-empty p { font-size:.875rem; color:var(--muted); }

/* ── TOAST ── */
.pg-toast {
  position:fixed; bottom:26px; right:26px; z-index:2000;
  background:var(--sage-d); color:#fff; border-radius:50px;
  padding:13px 22px; font-size:.875rem; font-weight:500;
  box-shadow:0 8px 32px rgba(0,0,0,.2);
  display:flex; align-items:center; gap:10px;
  transform:translateY(80px); opacity:0;
  transition:all .35s cubic-bezier(.34,1.46,.64,1);
}
.pg-toast.show { transform:translateY(0); opacity:1; }

/* ── SCROLL REVEAL ── */
.reveal { opacity:0; transform:translateY(24px); transition:opacity .65s ease,transform .65s ease; }
.reveal.visible { opacity:1; transform:none; }

/* ── ANIMATIONS ── */
@keyframes fadeUp   { from{opacity:0;transform:translateY(28px)} to{opacity:1;transform:none} }
@keyframes fadeIn   { from{opacity:0} to{opacity:1} }
@keyframes popIn    { from{opacity:0;transform:scale(.9)} to{opacity:1;transform:scale(1)} }
@keyframes orbDrift {
  0%,100%{transform:translate(0,0) scale(1)}
  40%{transform:translate(40px,-30px) scale(1.08)}
  70%{transform:translate(-20px,20px) scale(.96)}
}
@keyframes shimmer  { 0%{background-position:200% 0} 100%{background-position:-200% 0} }

/* ── RESPONSIVE ── */
@media(max-width:1100px) { .pg-grid{grid-template-columns:repeat(auto-fill,minmax(220px,1fr));} }
@media(max-width:680px) {
  .pg-hero{padding:56px 16px 72px;}
  .hero-stats{gap:24px;}
  .pg-grid{grid-template-columns:repeat(auto-fill,minmax(155px,1fr));gap:14px;}
  .pg-card.list-view{grid-template-columns:1fr;}
  .pg-modal-feats{grid-template-columns:1fr;}
  .pg-modal-body{padding:18px 16px 24px;}
  .pg-bar-inner{flex-wrap:wrap;}
}
