import React, { useState, useEffect, useRef } from "react";
import { useNavigate } from "react-router-dom";
import Nav from "./Nev";

// ─── Config ───────────────────────────────────────────────────
const WHATSAPP_NUMBER = "919999999999"; // 👈 Apna number daal do
const API_URL = "http://localhost/Petshop/show.php";

// ─── Category mapping ─────────────────────────────────────────
const CAT_MAP = {
  Affenpinscher: "Dogs", Alaskan: "Dogs", "Alaskan Malamute": "Dogs",
  "Airedale Terrier": "Dogs", "Dog Breeds": "Dogs", Husky: "Dogs",
  Labrador: "Dogs", "Golden Retriever": "Dogs",
  "Persian Cat": "Cats", "Maine Coon": "Cats", Siamese: "Cats",
  "Indian Ringneck": "Birds", Parrot: "Birds", Cockatiel: "Birds",
  Arowana: "Fish", Goldfish: "Fish", Betta: "Fish",
  "Lop-eared Rabbit": "Rabbits", Rabbit: "Rabbits",
  "Bearded Dragon": "Exotic", Iguana: "Exotic",
};
const getCategory = (name) => CAT_MAP[name] || "Dogs";

const DESC_MAP = {
  Affenpinscher:      "Playful, curious & fearless. The perfect apartment companion.",
  Alaskan:            "Energetic sled breed that thrives on outdoor adventures.",
  "Alaskan Malamute": "Powerful & loyal. Built for active families who love the wild.",
  "Airedale Terrier": "King of terriers — intelligent, outgoing & supremely confident.",
  "Dog Breeds":       "Premium mixed-breed companion with exceptional temperament.",
};
const getDesc = (name) =>
  DESC_MAP[name] || "A healthy, vaccinated & lovingly trained companion awaiting its forever home.";

const BADGE_DATA = [
  { label: "POPULAR",  cls: "badge-popular"  },
  { label: "NEW",      cls: "badge-new"       },
  { label: "PREMIUM",  cls: "badge-premium"   },
  { label: "VERIFIED", cls: "badge-verified"  },
];
const getBadge   = (id) => BADGE_DATA[(id - 1) % BADGE_DATA.length];
const AGES       = ["8 weeks","10 weeks","3 months","2 months","12 weeks","6 months"];
const getAge     = (id) => AGES[id % AGES.length];
const getRating  = (id) => +(4.5 + ((id * 7) % 5) / 10).toFixed(1);
const getReviews = (id) => 40 + ((id * 37) % 200);

const CATEGORIES = ["All","Dogs","Cats","Birds","Fish","Rabbits","Exotic"];
const CAT_ICONS  = { All:"🐾", Dogs:"🐕", Cats:"🐈", Birds:"🦜", Fish:"🐠", Rabbits:"🐇", Exotic:"🦎" };

const FALLBACK_IMGS = [
  "https://images.unsplash.com/photo-1587300003388-59208cc962cb?w=600&q=80",
  "https://images.unsplash.com/photo-1548199973-03cce0bbc87b?w=600&q=80",
  "https://images.unsplash.com/photo-1537151608828-ea2b11777ee8?w=600&q=80",
  "https://images.unsplash.com/photo-1583511655857-d19b40a7a54e?w=600&q=80",
  "https://images.unsplash.com/photo-1601979031925-424e53b6caaa?w=600&q=80",
  "https://images.unsplash.com/photo-1518717758536-85ae29035b6d?w=600&q=80",
];

const starsStr = (r) => {
  const f = Math.floor(r), h = r % 1 >= 0.5;
  return "★".repeat(f) + (h ? "½" : "") + "☆".repeat(5 - f - (h ? 1 : 0));
};

// ─── CSS — Petology Luxury Design System ──────────────────────
const css = `
@import url('https://fonts.googleapis.com/css2?family=Cormorant+Garamond:ital,wght@0,400;0,600;0,700;1,400;1,700&family=Outfit:wght@300;400;500;600;700&display=swap');

:root {
  --bg:      #f4f1eb;
  --bg2:     #ede8de;
  --surface: #ffffff;
  --card:    #faf8f4;
  --sage:    #3d6b4f;
  --sage-d:  #2a4e39;
  --sage-l:  #5a9470;
  --sage-xs: rgba(61,107,79,0.09);
  --sage-sm: rgba(61,107,79,0.18);
  --gold:    #b8922a;
  --gold-l:  #d4ac48;
  --gold-xs: rgba(184,146,42,0.12);
  --border:  rgba(61,107,79,0.13);
  --border2: rgba(184,146,42,0.18);
  --text:    #1c2b22;
  --text2:   #3a4a3f;
  --muted:   #7a907f;
  --dim:     #aab8ac;
  --ivory:   #fdf9f2;
  --shadow:    0 4px 24px rgba(30,50,35,0.08);
  --shadow-lg: 0 16px 60px rgba(30,50,35,0.14);
  --radius:  20px;
}

*,:after,:before { box-sizing:border-box; margin:0; padding:0; }

::-webkit-scrollbar { width:5px; }
::-webkit-scrollbar-thumb { background:var(--sage); border-radius:10px; }

.pg { min-height:100vh; background:var(--bg); font-family:'Outfit',sans-serif; color:var(--text); }

/* ── label-tag eyebrow ── */
.label-tag {
  font-size:0.7rem; font-weight:700; letter-spacing:0.2em;
  text-transform:uppercase; color:var(--sage);
  display:flex; align-items:center; gap:8px;
}
.label-tag::before { content:''; width:24px; height:2px; background:var(--sage); border-radius:2px; flex-shrink:0; }

/* ── Buttons ── */
.btn-sage {
  display:inline-flex; align-items:center; gap:8px;
  padding:11px 26px; border-radius:50px; border:none; cursor:pointer;
  font-family:'Outfit',sans-serif; font-size:.875rem; font-weight:600;
  background:var(--sage-l); color:#fff;
  box-shadow:0 4px 18px rgba(61,107,79,0.28);
  transition:all .22s ease;
}
.btn-sage:hover { background:var(--sage-d); transform:translateY(-2px); box-shadow:0 8px 24px rgba(61,107,79,0.36); }
.btn-sage.added { background:#1D9E75; }

.btn-gold {
  display:inline-flex; align-items:center; gap:8px;
  padding:12px 28px; border-radius:50px; border:none; cursor:pointer;
  font-family:'Outfit',sans-serif; font-size:.9rem; font-weight:600;
  background:var(--gold); color:#fff;
  box-shadow:0 4px 18px rgba(184,146,42,0.3);
  transition:all .22s ease;
}
.btn-gold:hover { background:#9c7a1e; transform:translateY(-2px); }

.btn-icon {
  width:38px; height:38px; border-radius:50%; border:1.5px solid var(--border);
  background:transparent; cursor:pointer; font-size:16px;
  display:flex; align-items:center; justify-content:center;
  transition:all .2s; color:var(--muted); font-family:'Outfit',sans-serif;
}
.btn-icon:hover,.btn-icon.active {
  background:var(--sage-xs); border-color:var(--sage); color:var(--sage);
}

/* ── HERO ── */
.pg-hero {
  background:linear-gradient(160deg,#1e3a28,#2a5a3c,#1a4030);
  padding:80px 24px 96px; text-align:center;
  position:relative; overflow:hidden;
}
.hero-orb {
  position:absolute; border-radius:50%;
  filter:blur(80px); opacity:.18; pointer-events:none;
  animation:orbDrift 14s ease-in-out infinite;
}
.hero-orb-1 { width:380px; height:380px; background:var(--sage-l); top:-80px; left:-80px; }
.hero-orb-2 { width:280px; height:280px; background:var(--gold-l); bottom:-40px; right:-40px; animation-delay:-6s; }
.hero-wave {
  position:absolute; bottom:0; left:0; right:0; height:64px;
  background:var(--bg); clip-path:ellipse(58% 100% at 50% 100%);
}
.hero-inner { position:relative; z-index:2; max-width:800px; margin:0 auto; }
.hero-pill {
  display:inline-flex; align-items:center; gap:8px;
  background:rgba(255,255,255,.1); border:1px solid rgba(255,255,255,.2);
  color:rgba(255,255,255,.85); font-size:.72rem; font-weight:600;
  letter-spacing:.2em; text-transform:uppercase;
  padding:7px 20px; border-radius:50px; margin-bottom:22px;
  animation:fadeUp .5s ease;
}
.hero-inner h1 {
  font-family:'Cormorant Garamond',serif;
  font-size:clamp(38px,6vw,72px); font-weight:700; line-height:1.08;
  color:#fff; margin-bottom:16px; animation:fadeUp .6s ease;
}
.hero-inner h1 em { font-style:italic; color:#a8d4b8; }
.hero-inner p {
  color:rgba(255,255,255,.52); font-size:1rem; font-weight:300;
  max-width:480px; margin:0 auto 38px; line-height:1.75;
  animation:fadeUp .7s ease;
}
.hero-stats {
  display:flex; justify-content:center; gap:48px; flex-wrap:wrap;
  animation:fadeUp .8s ease;
}
.h-stat-num {
  font-family:'Cormorant Garamond',serif;
  font-size:2rem; font-weight:700; color:#a8d4b8; display:block;
}
.h-stat-lbl {
  font-size:.68rem; color:rgba(255,255,255,.4);
  letter-spacing:.18em; text-transform:uppercase;
}

/* ── SEARCH BAR ── */
.pg-bar { max-width:1100px; margin:-26px auto 0; padding:0 20px; position:relative; z-index:10; }
.pg-bar-inner {
  background:var(--surface); border-radius:var(--radius);
  padding:18px 22px;
  box-shadow:0 12px 48px rgba(30,50,35,.13),0 2px 8px rgba(30,50,35,.06);
  border:1px solid var(--border);
  display:flex; gap:12px; align-items:center; flex-wrap:wrap;
}
.pg-search {
  flex:1; min-width:200px;
  display:flex; align-items:center; gap:10px;
  background:var(--bg); border:1.5px solid var(--border);
  border-radius:50px; padding:10px 18px; transition:all .2s;
}
.pg-search:focus-within { border-color:var(--sage); box-shadow:0 0 0 3px rgba(61,107,79,.1); }
.pg-search-icon { font-size:15px; opacity:.5; flex-shrink:0; }
.pg-search input {
  border:none; background:transparent; outline:none;
  font-family:'Outfit',sans-serif; font-size:.875rem; color:var(--text); width:100%;
}
.pg-search input::placeholder { color:var(--dim); }
.pg-sort {
  background:var(--bg); border:1.5px solid var(--border); border-radius:50px;
  padding:10px 16px; font-family:'Outfit',sans-serif; font-size:.85rem;
  font-weight:500; color:var(--text); cursor:pointer; outline:none;
  transition:border-color .2s;
}
.pg-sort:focus { border-color:var(--sage); }
.pg-view-btns { display:flex; gap:6px; }

/* ── CATEGORY CHIPS ── */
.pg-cats {
  max-width:1100px; margin:18px auto 0; padding:0 20px;
  display:flex; gap:8px; flex-wrap:wrap;
}
.pg-cat {
  padding:8px 18px; border-radius:50px;
  border:1.5px solid var(--border); background:var(--surface);
  color:var(--muted); font-family:'Outfit',sans-serif;
  font-size:.8rem; font-weight:500; cursor:pointer; transition:all .2s;
  display:flex; align-items:center; gap:6px;
}
.pg-cat:hover { border-color:var(--sage); color:var(--sage); transform:translateY(-1px); }
.pg-cat.active {
  background:var(--sage); border-color:var(--sage); color:#fff;
  box-shadow:0 4px 16px rgba(61,107,79,.3);
}
.pg-cat-cnt {
  font-size:.68rem; padding:1px 7px; border-radius:50px;
  background:rgba(0,0,0,.08); color:inherit;
}
.pg-cat.active .pg-cat-cnt { background:rgba(255,255,255,.25); }

/* ── INFO ROW ── */
.pg-info {
  max-width:1100px; margin:20px auto 0; padding:0 20px;
  display:flex; justify-content:space-between; align-items:center;
}
.pg-results { font-size:.82rem; color:var(--muted); }
.pg-results strong { color:var(--text); font-weight:600; }
.pg-clear {
  font-size:.78rem; color:var(--sage); cursor:pointer; font-weight:600;
  background:none; border:none; font-family:'Outfit',sans-serif;
}
.pg-clear:hover { text-decoration:underline; }

/* ── GRID ── */
.pg-grid {
  max-width:1100px; margin:20px auto 0; padding:0 20px 100px;
  display:grid; gap:22px;
  grid-template-columns:repeat(auto-fill,minmax(252px,1fr));
}
.pg-grid.list-view { grid-template-columns:1fr; }

/* ── CARD ── */
.pg-card {
  background:var(--surface); border-radius:var(--radius);
  border:1px solid var(--border); overflow:hidden;
  cursor:pointer; position:relative; box-shadow:var(--shadow);
  transition:transform .4s cubic-bezier(.34,1.56,.64,1),
             box-shadow .4s ease, border-color .3s ease;
  animation:fadeUp .45s ease both;
}
.pg-card:hover {
  transform:translateY(-10px);
  box-shadow:0 20px 60px rgba(30,50,35,.16),0 4px 12px rgba(30,50,35,.08);
  border-color:rgba(61,107,79,.3);
}
.pg-card.list-view { display:grid; grid-template-columns:230px 1fr; border-radius:16px; }
.pg-card.list-view:hover { transform:translateY(-5px); }

/* Image */
.pg-img-wrap { position:relative; overflow:hidden; aspect-ratio:4/3; background:var(--bg2); }
.pg-card.list-view .pg-img-wrap { aspect-ratio:unset; min-height:190px; }
.pg-img {
  width:100%; height:100%; object-fit:cover;
  transition:transform .55s cubic-bezier(.25,.46,.45,.94);
}
.pg-card:hover .pg-img { transform:scale(1.07); }

/* Badges */
.pg-badge {
  position:absolute; top:12px; left:12px;
  padding:4px 11px; border-radius:50px;
  font-size:.65rem; font-weight:700; letter-spacing:.1em;
  text-transform:uppercase; color:#fff;
}
.badge-popular  { background:var(--sage); }
.badge-new      { background:#3ecf8e; }
.badge-premium  { background:#7c5cfc; }
.badge-verified { background:var(--gold); }

/* Wishlist */
.pg-wish {
  position:absolute; top:12px; right:12px;
  width:34px; height:34px; border-radius:50%;
  background:rgba(255,255,255,.92); border:none; cursor:pointer;
  display:flex; align-items:center; justify-content:center;
  font-size:16px; backdrop-filter:blur(6px);
  transition:all .25s; opacity:0; transform:scale(.7);
}
.pg-card:hover .pg-wish { opacity:1; transform:scale(1); }
.pg-wish.liked { opacity:1; transform:scale(1); }
.pg-wish:hover { transform:scale(1.18) !important; }

/* Quick view pill */
.pg-quick {
  position:absolute; bottom:12px; left:50%;
  transform:translateX(-50%) translateY(10px);
  background:rgba(255,255,255,.96); border:none; border-radius:50px;
  padding:7px 18px; font-family:'Outfit',sans-serif; font-size:.75rem;
  font-weight:600; color:var(--sage-d); cursor:pointer; white-space:nowrap;
  opacity:0; transition:all .25s; backdrop-filter:blur(6px);
  box-shadow:0 4px 16px rgba(0,0,0,.12);
}
.pg-card:hover .pg-quick { opacity:1; transform:translateX(-50%) translateY(0); }

/* Body */
.pg-body { padding:18px 18px 16px; }
.pg-card.list-view .pg-body { padding:22px 26px; display:flex; flex-direction:column; justify-content:center; }
.pg-cat-tag {
  font-size:.68rem; font-weight:700; letter-spacing:.18em; text-transform:uppercase;
  color:var(--sage); margin-bottom:6px; display:flex; align-items:center; gap:5px;
}
.pg-cat-tag::before { content:''; display:inline-block; width:5px; height:5px; border-radius:50%; background:var(--sage-l); }
.pg-pname {
  font-family:'Cormorant Garamond',serif;
  font-size:1.25rem; font-weight:700; color:var(--text); margin:0 0 3px; line-height:1.25;
}
.pg-card.list-view .pg-pname { font-size:1.55rem; }
.pg-age { font-size:.75rem; color:var(--muted); margin-bottom:6px; }
.pg-desc { font-size:.8rem; color:var(--muted); line-height:1.65; margin-bottom:10px; display:none; }
.pg-card.list-view .pg-desc { display:block; }
.pg-rating { display:flex; align-items:center; gap:5px; margin-bottom:13px; }
.pg-stars { color:var(--gold); font-size:.75rem; letter-spacing:1px; }
.pg-rev   { font-size:.7rem; color:var(--dim); }
.pg-price-row { display:flex; align-items:center; justify-content:space-between; gap:8px; }
.pg-price {
  font-family:'Cormorant Garamond',serif;
  font-size:1.55rem; font-weight:700; color:var(--sage-d); line-height:1;
}
.pg-price sup { font-size:.85rem; font-family:'Outfit',sans-serif; font-weight:500; color:var(--muted); }
.pg-btns { display:flex; gap:7px; align-items:center; }
.pg-cart-btn {
  padding:8px 15px; border-radius:50px; border:none;
  background:var(--sage-l); color:#fff;
  font-family:'Outfit',sans-serif; font-size:.75rem; font-weight:600;
  cursor:pointer; transition:all .22s; white-space:nowrap;
  display:flex; align-items:center; gap:5px;
  box-shadow:0 4px 12px rgba(61,107,79,.25);
}
.pg-cart-btn:hover { background:var(--sage-d); transform:translateY(-1px); }
.pg-cart-btn.added { background:#1D9E75; }
.pg-wa-btn {
  width:34px; height:34px; border-radius:50%;
  border:1.5px solid var(--border2); background:var(--gold-xs);
  cursor:pointer; font-size:15px; transition:all .2s;
  display:flex; align-items:center; justify-content:center; flex-shrink:0;
}
.pg-wa-btn:hover { border-color:var(--gold); transform:scale(1.1); }

/* ── MODAL ── */
.pg-modal-bg {
  position:fixed; inset:0; background:rgba(10,22,14,.72);
  z-index:1000; display:flex; align-items:center; justify-content:center;
  padding:20px; backdrop-filter:blur(8px); animation:fadeIn .2s ease;
}
.pg-modal {
  background:var(--ivory); border-radius:var(--radius);
  max-width:680px; width:100%; max-height:90vh;
  overflow-y:auto; position:relative;
  box-shadow:var(--shadow-lg),0 48px 100px rgba(0,0,0,.25);
  border:1px solid var(--border);
  animation:popIn .3s cubic-bezier(.34,1.46,.64,1);
}
.pg-modal-img { width:100%; height:290px; object-fit:cover; border-radius:var(--radius) var(--radius) 0 0; }
.pg-modal-close {
  position:absolute; top:14px; right:14px;
  width:36px; height:36px; border-radius:50%;
  background:rgba(255,255,255,.95); border:none;
  font-size:16px; cursor:pointer; color:var(--text);
  display:flex; align-items:center; justify-content:center;
  box-shadow:0 2px 12px rgba(0,0,0,.12); transition:all .22s;
}
.pg-modal-close:hover { transform:rotate(90deg) scale(1.1); }
.pg-modal-body { padding:26px 30px 32px; }
.pg-modal-name {
  font-family:'Cormorant Garamond',serif;
  font-size:1.9rem; font-weight:700; color:var(--text); margin:0 0 8px;
}
.pg-modal-price {
  font-family:'Cormorant Garamond',serif;
  font-size:2.1rem; font-weight:700; color:var(--sage-d); margin:0 0 18px;
}
.pg-modal-feats { display:grid; grid-template-columns:1fr 1fr; gap:10px; margin-bottom:22px; }
.pg-feat {
  background:var(--bg); border:1px solid var(--border);
  border-radius:14px; padding:12px 14px;
  font-size:.8rem; color:var(--muted);
}
.pg-feat strong { display:block; font-size:.85rem; font-weight:600; color:var(--text2); margin-bottom:3px; }
.pg-modal-actions { display:flex; gap:10px; flex-wrap:wrap; margin-bottom:10px; }
.pg-modal-cart-btn {
  flex:1; min-width:140px; padding:13px 20px;
  background:var(--sage-l); color:#fff; border:none; border-radius:50px;
  font-family:'Outfit',sans-serif; font-size:.9rem; font-weight:600;
  cursor:pointer; transition:all .22s;
  display:flex; align-items:center; justify-content:center; gap:8px;
  box-shadow:0 6px 20px rgba(61,107,79,.3);
}
.pg-modal-cart-btn:hover { background:var(--sage-d); transform:translateY(-2px); }
.pg-modal-wa-btn {
  padding:13px 22px; border-radius:50px;
  border:1.5px solid var(--border2); background:var(--gold-xs);
  font-family:'Outfit',sans-serif; font-size:.9rem; font-weight:600;
  color:var(--gold); cursor:pointer; transition:all .22s;
  display:flex; align-items:center; gap:7px;
}
.pg-modal-wa-btn:hover { background:var(--gold); color:#fff; transform:translateY(-2px); }
.pg-modal-wish-btn {
  padding:13px 16px; border-radius:50px;
  border:1.5px solid var(--border); background:transparent;
  font-size:18px; cursor:pointer; transition:all .2s;
}
.pg-modal-wish-btn:hover { border-color:#ef4444; background:#fff1f2; }
.pg-buynow {
  width:100%; padding:13px;
  background:linear-gradient(135deg,var(--gold),var(--gold-l));
  color:#fff; border:none; border-radius:50px;
  font-family:'Outfit',sans-serif; font-size:.9rem; font-weight:700;
  cursor:pointer; transition:all .22s;
  box-shadow:0 6px 20px rgba(184,146,42,.3);
  display:flex; align-items:center; justify-content:center; gap:8px;
}
.pg-buynow:hover { opacity:.88; transform:translateY(-2px); }

/* ── SKELETON ── */
.pg-skel { background:var(--surface); border-radius:var(--radius); overflow:hidden; border:1px solid var(--border); }
.pg-skel-img {
  height:190px;
  background:linear-gradient(90deg,var(--bg2) 25%,var(--bg) 50%,var(--bg2) 75%);
  background-size:200%; animation:shimmer 1.5s ease infinite;
}
.pg-skel-body { padding:18px; }
.pg-skel-line {
  height:11px; border-radius:6px; margin-bottom:10px;
  background:linear-gradient(90deg,var(--bg2) 25%,var(--bg) 50%,var(--bg2) 75%);
  background-size:200%; animation:shimmer 1.5s ease infinite;
}
.pg-skel-line.w70 { width:70%; }
.pg-skel-line.w50 { width:50%; }

/* ── EMPTY ── */
.pg-empty { grid-column:1/-1; text-align:center; padding:80px 20px; }
.pg-empty-icon { font-size:60px; display:block; margin-bottom:16px; }
.pg-empty h3 {
  font-family:'Cormorant Garamond',serif;
  font-size:1.5rem; font-weight:700; color:var(--text); margin:0 0 8px;
}
.pg-empty p { font-size:.875rem; color:var(--muted); }

/* ── TOAST ── */
.pg-toast {
  position:fixed; bottom:26px; right:26px; z-index:2000;
  background:var(--sage-d); color:#fff; border-radius:50px;
  padding:13px 22px; font-size:.875rem; font-weight:500;
  box-shadow:0 8px 32px rgba(0,0,0,.2);
  display:flex; align-items:center; gap:10px;
  transform:translateY(80px); opacity:0;
  transition:all .35s cubic-bezier(.34,1.46,.64,1);
}
.pg-toast.show { transform:translateY(0); opacity:1; }

/* ── SCROLL REVEAL ── */
.reveal { opacity:0; transform:translateY(24px); transition:opacity .65s ease,transform .65s ease; }
.reveal.visible { opacity:1; transform:none; }

/* ── ANIMATIONS ── */
@keyframes fadeUp   { from{opacity:0;transform:translateY(28px)} to{opacity:1;transform:none} }
@keyframes fadeIn   { from{opacity:0} to{opacity:1} }
@keyframes popIn    { from{opacity:0;transform:scale(.9)} to{opacity:1;transform:scale(1)} }
@keyframes orbDrift {
  0%,100%{transform:translate(0,0) scale(1)}
  40%{transform:translate(40px,-30px) scale(1.08)}
  70%{transform:translate(-20px,20px) scale(.96)}
}
@keyframes shimmer  { 0%{background-position:200% 0} 100%{background-position:-200% 0} }

/* ── RESPONSIVE ── */
@media(max-width:1100px) { .pg-grid{grid-template-columns:repeat(auto-fill,minmax(220px,1fr));} }
@media(max-width:680px) {
  .pg-hero{padding:56px 16px 72px;}
  .hero-stats{gap:24px;}
  .pg-grid{grid-template-columns:repeat(auto-fill,minmax(155px,1fr));gap:14px;}
  .pg-card.list-view{grid-template-columns:1fr;}
  .pg-modal-feats{grid-template-columns:1fr;}
  .pg-modal-body{padding:18px 16px 24px;}
  .pg-bar-inner{flex-wrap:wrap;}
}
`;

// ─── Component ────────────────────────────────────────────────
export default function PetGallery() {
  const [pets, setPets]           = useState([]);
  const [loading, setLoading]     = useState(true);
  const [search, setSearch]       = useState("");
  const [category, setCategory]   = useState("All");
  const [sort, setSort]           = useState("default");
  const [view, setView]           = useState("grid");
  const [wishlist, setWishlist]   = useState([]);
  const [cartAnim, setCartAnim]   = useState({});
  const [quickView, setQuickView] = useState(null);
  const [toast, setToast]         = useState({ show: false, msg: "" });
  const navigate = useNavigate();

  // ── Fetch ──
  useEffect(() => {
    fetch(API_URL)
      .then((r) => r.json())
      .then((data) => {
        const enriched = (data || [])
          .filter((p) => p.pname?.trim() && !isNaN(parseInt(p.price)))
          .map((p, i) => ({
            ...p,
            price:    parseInt(p.price) || 0,
            cat:      getCategory(p.pname),
            desc:     getDesc(p.pname),
            badge:    getBadge(parseInt(p.id)),
            age:      getAge(parseInt(p.id)),
            rating:   getRating(parseInt(p.id)),
            reviews:  getReviews(parseInt(p.id)),
            fallback: FALLBACK_IMGS[i % FALLBACK_IMGS.length],
          }));
        setPets(enriched);
        setLoading(false);
      })
      .catch(() => setLoading(false));
  }, []);

  // ── Scroll Reveal (IntersectionObserver) ──
  useEffect(() => {
    const io = new IntersectionObserver(
      (entries) => entries.forEach((e) => e.isIntersecting && e.target.classList.add("visible")),
      { threshold: 0.08 }
    );
    document.querySelectorAll(".reveal").forEach((el) => io.observe(el));
    return () => io.disconnect();
  }, [pets, loading, category, search]);

  // ── Filter + Sort ──
  const filtered = pets
    .filter((p) => category === "All" || p.cat === category)
    .filter((p) => p.pname.toLowerCase().includes(search.toLowerCase()))
    .sort((a, b) => {
      if (sort === "price-asc")  return a.price - b.price;
      if (sort === "price-desc") return b.price - a.price;
      if (sort === "rating")     return b.rating - a.rating;
      if (sort === "name")       return a.pname.localeCompare(b.pname);
      return 0;
    });

  const catCount = (c) =>
    c === "All" ? pets.length : pets.filter((p) => p.cat === c).length;

  // ── Helpers ──
  const showToast = (msg) => {
    setToast({ show: true, msg });
    setTimeout(() => setToast({ show: false, msg: "" }), 3000);
  };

  const toggleWish = (id, e) => {
    e?.stopPropagation();
    setWishlist((w) => w.includes(id) ? w.filter((x) => x !== id) : [...w, id]);
  };

  const addToCart = (pet, e) => {
    e?.stopPropagation();
    localStorage.setItem("item", pet.price);
    localStorage.setItem("pid", pet.id);
    if (!localStorage.getItem("id")) localStorage.setItem("id", 1);
    setCartAnim((a) => ({ ...a, [pet.id]: true }));
    setTimeout(() => setCartAnim((a) => ({ ...a, [pet.id]: false })), 1600);
    showToast(`🛒 ${pet.pname} added to cart!`);
  };

  const buyNow = (pet) => {
    addToCart(pet);
    setTimeout(() => navigate("/checkout"), 350);
  };

  const whatsappInquiry = (pet, e) => {
    e?.stopPropagation();
    const msg = encodeURIComponent(
      `Hi! I'm interested in *${pet.pname}* (${pet.age} old) listed at ₹${pet.price.toLocaleString("en-IN")}. Please share more details.`
    );
    window.open(`https://wa.me/${WHATSAPP_NUMBER}?text=${msg}`, "_blank");
  };

  const imgSrc = (pet) => pet.image || pet.fallback;

  return (
    <>
      <style>{css}</style>
      <div className="pg">
        <Nav />

        {/* ── HERO ── */}
        <div className="pg-hero">
          <div className="hero-orb hero-orb-1" />
          <div className="hero-orb hero-orb-2" />
          <div className="hero-inner">
            <div className="hero-pill">🐾 Premium Pet Marketplace</div>
            <h1>Find Your Perfect<br /><em>Companion</em></h1>
            <p>
              Hand-picked, vaccinated & health-certified pets from trusted<br />
              breeders across India — delivered to your door.
            </p>
            <div className="hero-stats">
              <div>
                <span className="h-stat-num">{pets.length || "50"}+</span>
                <span className="h-stat-lbl">Pets Available</span>
              </div>
              <div>
                <span className="h-stat-num">100%</span>
                <span className="h-stat-lbl">Health Verified</span>
              </div>
              <div>
                <span className="h-stat-num">4.9★</span>
                <span className="h-stat-lbl">Avg Rating</span>
              </div>
              <div>
                <span className="h-stat-num">Free</span>
                <span className="h-stat-lbl">Home Delivery</span>
              </div>
            </div>
          </div>
          <div className="hero-wave" />
        </div>

        {/* ── SEARCH BAR ── */}
        <div className="pg-bar reveal">
          <div className="pg-bar-inner">
            <div className="pg-search">
              <span className="pg-search-icon">🔍</span>
              <input
                placeholder="Search by breed or type..."
                value={search}
                onChange={(e) => setSearch(e.target.value)}
              />
            </div>
            <select className="pg-sort" value={sort} onChange={(e) => setSort(e.target.value)}>
              <option value="default">Sort: Featured</option>
              <option value="price-asc">Price: Low → High</option>
              <option value="price-desc">Price: High → Low</option>
              <option value="rating">Top Rated</option>
              <option value="name">A → Z</option>
            </select>
            <div className="pg-view-btns">
              <button className={`btn-icon ${view === "grid" ? "active" : ""}`} onClick={() => setView("grid")} title="Grid">⊞</button>
              <button className={`btn-icon ${view === "list" ? "active" : ""}`} onClick={() => setView("list")} title="List">☰</button>
            </div>
          </div>
        </div>

        {/* ── CATEGORY CHIPS ── */}
        <div className="pg-cats reveal">
          {CATEGORIES.map((cat) => (
            <button
              key={cat}
              className={`pg-cat ${category === cat ? "active" : ""}`}
              onClick={() => setCategory(cat)}
            >
              {CAT_ICONS[cat]} {cat}
              <span className="pg-cat-cnt">{catCount(cat)}</span>
            </button>
          ))}
        </div>

        {/* ── INFO ROW ── */}
        <div className="pg-info">
          <span className="pg-results">
            Showing <strong>{filtered.length}</strong> of <strong>{pets.length}</strong> pets
            {search && <> matching "<strong>{search}</strong>"</>}
          </span>
          {(search || category !== "All") && (
            <button className="pg-clear" onClick={() => { setSearch(""); setCategory("All"); }}>
              Clear filters ✕
            </button>
          )}
        </div>

        {/* ── PET GRID ── */}
        <div className={`pg-grid ${view === "list" ? "list-view" : ""}`}>
          {loading
            ? Array(8).fill(0).map((_, i) => (
                <div className="pg-skel" key={i}>
                  <div className="pg-skel-img" />
                  <div className="pg-skel-body">
                    <div className="pg-skel-line" />
                    <div className="pg-skel-line w70" />
                    <div className="pg-skel-line w50" />
                  </div>
                </div>
              ))
            : filtered.length === 0
            ? (
              <div className="pg-empty">
                <span className="pg-empty-icon">🐾</span>
                <h3>No pets found</h3>
                <p>Try adjusting your search or filters</p>
              </div>
            )
            : filtered.map((pet, i) => (
              <div
                key={pet.id}
                className={`pg-card reveal ${view === "list" ? "list-view" : ""}`}
                style={{ animationDelay: (i % 12) * 0.05 + "s", transitionDelay: (i % 12) * 0.04 + "s" }}
                onClick={() => setQuickView(pet)}
              >
                <div className="pg-img-wrap">
                  <img
                    src={imgSrc(pet)}
                    alt={pet.pname}
                    className="pg-img"
                    onError={(e) => { e.target.src = pet.fallback; }}
                  />
                  <span className={`pg-badge ${pet.badge.cls}`}>{pet.badge.label}</span>
                  <button
                    className={`pg-wish ${wishlist.includes(pet.id) ? "liked" : ""}`}
                    onClick={(e) => toggleWish(pet.id, e)}
                  >
                    {wishlist.includes(pet.id) ? "❤️" : "🤍"}
                  </button>
                  <button
                    className="pg-quick"
                    onClick={(e) => { e.stopPropagation(); setQuickView(pet); }}
                  >
                    Quick View →
                  </button>
                </div>
                <div className="pg-body">
                  <div className="pg-cat-tag">{pet.cat}</div>
                  <div className="pg-pname">{pet.pname}</div>
                  <div className="pg-age">🐣 {pet.age} old</div>
                  <div className="pg-desc">{pet.desc}</div>
                  <div className="pg-rating">
                    <span className="pg-stars">{starsStr(pet.rating)}</span>
                    <span className="pg-rev">({pet.reviews} reviews)</span>
                  </div>
                  <div className="pg-price-row">
                    <div className="pg-price">
                      <sup>₹</sup>{pet.price.toLocaleString("en-IN")}
                    </div>
                    <div className="pg-btns">
                      <button
                        className={`pg-cart-btn ${cartAnim[pet.id] ? "added" : ""}`}
                        onClick={(e) => addToCart(pet, e)}
                      >
                        {cartAnim[pet.id] ? "✓ Added" : "🛒 Add"}
                      </button>
                      <button
                        className="pg-wa-btn"
                        title="WhatsApp Inquiry"
                        onClick={(e) => whatsappInquiry(pet, e)}
                      >
                        💬
                      </button>
                    </div>
                  </div>
                </div>
              </div>
            ))
          }
        </div>

        {/* ── QUICK VIEW MODAL ── */}
        {quickView && (
          <div className="pg-modal-bg" onClick={() => setQuickView(null)}>
            <div className="pg-modal" onClick={(e) => e.stopPropagation()}>
              <img
                src={imgSrc(quickView)}
                alt={quickView.pname}
                className="pg-modal-img"
                onError={(e) => { e.target.src = quickView.fallback; }}
              />
              <button className="pg-modal-close" onClick={() => setQuickView(null)}>✕</button>
              <div className="pg-modal-body">
                <div className="pg-cat-tag" style={{ marginBottom: 8 }}>{quickView.cat}</div>
                <div className="pg-modal-name">{quickView.pname}</div>
                <div style={{ display:"flex", alignItems:"center", gap:10, marginBottom:10 }}>
                  <div className="pg-rating" style={{ margin:0 }}>
                    <span className="pg-stars">{starsStr(quickView.rating)}</span>
                    <span className="pg-rev">({quickView.reviews} verified reviews)</span>
                  </div>
                  <span className={`pg-badge ${quickView.badge.cls}`} style={{ position:"static" }}>
                    {quickView.badge.label}
                  </span>
                </div>
                <div className="pg-modal-price">₹{quickView.price.toLocaleString("en-IN")}</div>
                <p style={{ fontSize:".875rem", color:"var(--muted)", lineHeight:1.75, marginBottom:20 }}>
                  {quickView.desc} Comes with health certificate, vaccination record & a 7-day health guarantee.
                </p>
                <div className="pg-modal-feats">
                  {[
                    { label:"Health Status", val:"✅ Vaccinated & Certified" },
                    { label:"Delivery",      val:"🚚 Free Pan India"         },
                    { label:"Age",           val:`🐣 ${quickView.age} old`   },
                    { label:"Guarantee",     val:"🛡️ 7-day Health Cover"     },
                  ].map((f, i) => (
                    <div className="pg-feat" key={i}>
                      <strong>{f.label}</strong>{f.val}
                    </div>
                  ))}
                </div>
                <div className="pg-modal-actions">
                  <button
                    className="pg-modal-cart-btn"
                    onClick={() => { addToCart(quickView); setQuickView(null); }}
                  >
                    🛒 Add to Cart — ₹{quickView.price.toLocaleString("en-IN")}
                  </button>
                  <button
                    className="pg-modal-wa-btn"
                    onClick={(e) => whatsappInquiry(quickView, e)}
                  >
                    💬 WhatsApp
                  </button>
                  <button
                    className="pg-modal-wish-btn"
                    onClick={(e) => toggleWish(quickView.id, e)}
                  >
                    {wishlist.includes(quickView.id) ? "❤️" : "🤍"}
                  </button>
                </div>
                <button
                  className="pg-buynow"
                  onClick={() => { setQuickView(null); buyNow(quickView); }}
                >
                  ⚡ Buy Now
                </button>
              </div>
            </div>
          </div>
        )}

        {/* ── TOAST ── */}
        <div className={`pg-toast ${toast.show ? "show" : ""}`}>
          {toast.msg}
        </div>
      </div>
    </>
  );
}
